import bisect
from collections import defaultdict
from dataclasses import asdict
from typing import TYPE_CHECKING

from django.utils import timezone

from cloud.fieldsales.models import ScoredSlots, SlotWithScore, SlotWithTravelTime

if TYPE_CHECKING:
    import datetime


def rank_slots(
    available_slots: list[SlotWithTravelTime],
    rank_slots=True,
    time_weight: float = 0.25,
) -> ScoredSlots:
    """
    Rank the available slots based on the travel time to the slot, and the time until the slot starts

    Args:
        available_slots: The available slots for the agent
        mark_best: Should the method set slot_type of slots
        time_weight: the weighting given to the time until appointment

    Returns:
        The best slot, the second and third best slots. In addition, all slots (including the three best
        slots) are grouped by date and sorted in chronological order.

    """
    if not available_slots:
        return ScoredSlots()
    now = timezone.now()
    slots_with_travel_time_and_time_until_appointment: list[tuple[SlotWithTravelTime, int, int]] = [
        (slot, slot.combined_travel_duration, slot.get_time_until_appointment(now))
        for slot in available_slots
    ]

    max_travel_time = max(slots_with_travel_time_and_time_until_appointment, key=lambda x: x[1])[1]
    max_time_until_appointment = max(slots_with_travel_time_and_time_until_appointment, key=lambda x: x[2])[2]

    scored_slots = [
        SlotWithScore(
            **asdict(slot),
            score=score_slot(
                travel_time=travel_time,
                time_until_appointment=time_until_appointment,
                max_travel_time=max_travel_time,
                max_time_until_appointment=max_time_until_appointment,
                time_weight=time_weight,
            ),
        )
        for slot, travel_time, time_until_appointment in slots_with_travel_time_and_time_until_appointment
    ]

    # Sort slots by score to find the best slots
    scored_slots.sort(key=lambda x: x.score, reverse=True)

    prefered_slots: list[SlotWithScore] = []

    slots_by_date: defaultdict[datetime.date, list[list[SlotWithScore]]] = defaultdict(list)
    for i, scored_slot in enumerate(scored_slots, start=1):
        if rank_slots:
            scored_slot.rank = i
            if i < 4:
                prefered_slots.append(scored_slot)
        # Keep the slots sorted by starting time for each day, and by score for each starting time
        day = slots_by_date[scored_slot.start_time.date()]
        idx = bisect.bisect_left(
            day,
            scored_slot.start_time,
            key=lambda x: x[0].start_time,
        )

        if idx >= len(day):
            day.append([scored_slot])
        elif day[idx][0].start_time == scored_slot.start_time:
            day[idx].append(scored_slot)
        else:
            day.insert(idx, [scored_slot])

    return ScoredSlots(all_slots=slots_by_date, preferred_slots=prefered_slots)


def score_slot(
    *,
    travel_time: int,
    time_until_appointment: int,
    max_travel_time: int,
    max_time_until_appointment: int,
    time_weight: float = 0.25,
) -> float:
    normalized_driving_time = 1 - (travel_time / max_travel_time)

    normalized_time_until_appointment = 1 - (time_until_appointment / max_time_until_appointment)

    driving_weight = 1 - time_weight
    return (driving_weight * normalized_driving_time) + (time_weight * normalized_time_until_appointment)
