    def __str__(self) -> str:
        return f'Event {self.slot_as_str()}'

    def slot_as_str(self, timezone=UTC_TZ):
        start_time = self.slot.lower.astimezone(timezone)
        end_time = self.slot.upper.astimezone(timezone)
        return self.format_slot(start_time, end_time)

    @property
    def readable_travel_time(self) -> str:
        td = self.travel_time.upper - self.travel_time.lower
        return self.format_duration(td.total_seconds())

    @classmethod
    def format_slot(cls, start_time: datetime.datetime, end_time: datetime.datetime) -> str:
        return '{start_time:%a. %-d %b, %H:%M} - {end_time:%H:%M}'.format(
            start_time=start_time, end_time=end_time
        )

    @classmethod
    def format_duration(cls, total_seconds: int | float) -> str:
        resolutions = [('d', 60 * 60 * 24), ('h', 60 * 60), ('min', 60)]
        result = ''
        remainder = int(total_seconds)
        for display, res in resolutions:
            value, remainder = divmod(remainder, res)
            if value:
                result += f' {value}{display}'

        return result.strip()

    @cached_property
    def customer(self) -> Customer:
        assert self.interest.customer is not None, 'Attempted to create agent calendar event without customer'
        return self.interest.customer

    def update_travel_time(self, blocking=True):
        """
        Update the travel time for the calendar event.

        Args:
            new_address (Address): The new address where the travel to this event will start from,
                if None, we will search for the location
        Returns:
            None
        """
        if not blocking:
            from cloud.fieldsales.tasks import update_travel_time

            update_travel_time.delay(self.id)
            return

        if not self.location:
            return

        new_location = self.schedule.base_address
        if event_before := self.agent.get_event_before_slot(self.slot):
            new_location = event_before.location or new_location
        if not new_location:
            return

        if not (
            distance_preceeding := Distance.get_distance(from_address=new_location, to_address=self.location)
        ):
            return

        new_travel_minutes = timedelta(minutes=distance_preceeding.minutes) + self.agent.buffer_duration

        travel_time = DateTimeTZRange(
            self.slot.lower - new_travel_minutes,
            self.slot.lower,
            bounds='[)',
        )

        if (
            conflict := self.agent.calendar_events.filter(
                Q(slot__overlap=travel_time) | Q(travel_time__overlap=travel_time)
            )
            .exclude(id=self.id)
            .first()
        ):
            logger.error(
                'New travel start on event %s: from %s to %s confilcts with existing event %s',
                self.id,
                self.travel_time.lower,
                travel_time.lower,
                conflict.id,
            )

        self.travel_time = travel_time
        self.save(update_fields=['travel_time'])

        update_body = {
            'start': {'dateTime': self.travel_time.lower.isoformat()},
            'end': {'dateTime': self.travel_time.upper.isoformat()},
        }
        update_gcal_event(
            event=self,
            gcal_id=self.travel_time_calendar_event_id,
            update_body=update_body,
        )

    def soft_delete(
        self,
        user: User,
        reason: MeetingCancellationReason = MeetingOutcome.CANCELED,
    ):
        from cloud.fieldsales.tasks import process_home_visit_cancellation

        self.deleted_at = timezone.now()
        self.save(update_fields=['deleted_at'])

        if event_after_slot := self.agent.get_event_after_slot(self.slot):
            event_after_slot.update_travel_time(blocking=False)

        process_home_visit_cancellation.delay(self.id, reason=reason)

        Event.home_vist_deleted(instance=self.interest, agent_calendar_event=self, user=user)

    @property
    def google_event_ids(self) -> list[str]:
        ids = []
        if self.appointment_calendar_event_id:
            ids.append(self.appointment_calendar_event_id)
        if self.travel_time_calendar_event_id:
            ids.append(self.travel_time_calendar_event_id)
        if self.customer_calendar_event_id:
            ids.append(self.customer_calendar_event_id)
        return ids

    @staticmethod
    def _get_google_event_link(event_id: str) -> str | None:
        if not event_id or not settings.GOOGLE_FIELD_SALES_EVENT_OWNER_CALENDAR_ID:
            return None
        formatted_id = f'{event_id} {settings.GOOGLE_FIELD_SALES_EVENT_OWNER_CALENDAR_ID}'
        encoded_id = base64.urlsafe_b64encode(formatted_id.encode()).decode().rstrip('=')
        return f'https://www.google.com/calendar/event?eid={encoded_id}'

    @property
    def google_event_links(self) -> dict[str, str | None]:
        return {
            'Travel event': self._get_google_event_link(self.travel_time_calendar_event_id),
            'Agent event': self._get_google_event_link(self.appointment_calendar_event_id),
            'Customer event': self._get_google_event_link(self.customer_calendar_event_id),
        }

    def get_customer_details_str(self) -> str:
        legal_contact = self.customer.legal_contact
        profile = getattr(legal_contact, 'profile', None)
        assert profile is not None, 'Need user profile to include customer details in calendar event'
        return (
            f'\n\nPhone: {profile.phone_number.as_e164}'
            f'\nInterest: {self.interest.get_absolute_url()}'
            f'\nHubSpot deal: {self.interest.get_hubspot_deal_url()}'
        )

    def build_travel_event_body(self) -> dict[str, Any]:
        address = self.location or self.interest.address
        customer_name = self.customer.legal_contact.get_full_name().title()
        with translation.override(self.interest.locale.value):
            summary = f'Travel to home visit - {customer_name}'
            if settings.ENVIRONMENT != 'production':
