def book_field_visit(request: OtovoRequest, pk: UUID) -> HttpResponse:
    interest = get_object_or_404(Interest, pk=pk)
    if not interest.customer:
        return HttpResponseBadRequest(
            'Please connect a customer to the interest before booking a field visit'
        )
    if request.method != 'POST':
        return HttpResponse(headers={'HX-Redirect': interest.get_absolute_url()})

    form = SlotDetailsForm(data=request.POST)
    if not form.is_valid():
        return HttpResponseBadRequest(f'Invalid slot: {form.errors.as_text()}')

    schedule: FieldSalesSchedule = form.cleaned_data['schedule']
    existing_event: AgentCalendarEvent | None = form.cleaned_data['existing_event']
    travel_to_destination_start_time = form.cleaned_data['travel_to_slot_start_time']
    start_time = form.cleaned_data['start_time']
    end_time = form.cleaned_data['end_time']
    rank = form.cleaned_data['rank']
    score = form.cleaned_data['score']
    appointment_slot = DateTimeTZRange(start_time, end_time, bounds='[)')
    field_sales_agent = schedule.agent
    travel_time_to_destination = DateTimeTZRange(travel_to_destination_start_time, start_time, bounds='[)')

    if existing_event and existing_event.agent != field_sales_agent:
        existing_event.soft_delete(request.user, reason=MeetingOutcome.RESCHEDULED)

    locked_agent_qs = FieldSalesAgent.objects.select_for_update().filter(id=field_sales_agent.id)
    with transaction.atomic():
        # Aquire a lock on the field agent and create or update the event
        agent = locked_agent_qs.get()

        conflicts = AgentCalendarEvent.objects.filter(agent=agent, slot__overlap=appointment_slot)
        if existing_event:
            conflicts = conflicts.exclude(id=existing_event.id)
        if conflict := conflicts.first():
            return HttpResponseBadRequest(
                f'Agent has a conflicting event booked at {conflict.slot_as_str(field_sales_agent.timezone)}'
            )
        if existing_event and not existing_event.deleted_at:
            old_slot = existing_event.slot
            existing_event.slot = appointment_slot
            existing_event.travel_time = travel_time_to_destination
            existing_event.rank = rank
            existing_event.score = score
            existing_event.schedule = schedule
            existing_event.save()
            Event.home_vist_rescheduled(
                instance=interest,
                agent_calendar_event=existing_event,
                user=request.user,
            )
            if old_event_after_slot := field_sales_agent.get_event_after_slot(old_slot):
                old_event_after_slot.update_travel_time(blocking=False)
            transaction.on_commit(lambda: update_home_visit_event.delay(existing_event.pk))
        else:
            home_visit_event = AgentCalendarEvent.objects.create(
                agent=agent,
                schedule=schedule,
                interest=interest,
                slot=appointment_slot,
                travel_time=travel_time_to_destination,
                location=interest.address,
                rank=rank,
                score=score,
            )
            Event.home_vist_scheduled(
                instance=interest,
                agent_calendar_event=home_visit_event,
                user=request.user,
            )
            transaction.on_commit(lambda: create_home_visit_event.delay(home_visit_event.pk))

        if event_after_slot := field_sales_agent.get_event_after_slot(appointment_slot):
            transaction.on_commit(lambda: event_after_slot.update_travel_time(blocking=False))

    if interest.agent != field_sales_agent:
        interest.change_agent(field_sales_agent.user, user=request.user)

    messages.success(
        request,
        'Field visit booked on {date}'.format(
            date=start_time.astimezone(field_sales_agent.timezone).strftime('%Y-%m-%d %H:%M')
        ),
    )
    return HttpResponse(headers={'HX-Redirect': interest.get_absolute_url()})


def delete_field_visit(request: OtovoRequest, pk: UUID) -> HttpResponse:
    agent_calendar_event = get_object_or_404(AgentCalendarEvent, pk=pk)
    if request.method != 'POST':
        return redirect(agent_calendar_event.interest.get_absolute_url())

    agent_calendar_event.soft_delete(request.user)

    messages.success(request, 'Field visit deleted successfully')
    context = {
        'home_visit_event': None,
        'interest': agent_calendar_event.interest,
        'today': timezone.now(),
    }
    return TemplateResponse(request, 'interests/interest_schedule_home_visit.html', context)
